// Etsy Templates
const tplItems = $('Etsy Template Search').all();
const etsyTemplates = tplItems.flatMap(item => {
  const results = item.json.results || [];
  return results.map(l => ({
    source: 'etsy_templates',
    title: l.title || '',
    price: l.price ? (l.price.amount / (l.price.divisor || 100)) : 0,
    favorites: l.num_favorers || 0,
    tags: (l.tags || []).join(', ')
  }));
});

// Etsy Ebooks
const ebkItems = $('Etsy Ebook Search').all();
const etsyEbooks = ebkItems.flatMap(item => {
  const results = item.json.results || [];
  return results.map(l => ({
    source: 'etsy_ebooks',
    title: l.title || '',
    price: l.price ? (l.price.amount / (l.price.divisor || 100)) : 0,
    favorites: l.num_favorers || 0,
    tags: (l.tags || []).join(', ')
  }));
});

// Competitive Intelligence (Claude + web search)
const ciItems = $('Claude \u2014 Competitive Intelligence').all();
const ciOpportunities = [];
for (const item of ciItems) {
  const content = item.json.content || [];
  const textBlocks = content.filter(b => b.type === 'text');
  for (const block of textBlocks) {
    const raw = block.text || '';
    const firstBracket = raw.indexOf('[');
    const lastBracket  = raw.lastIndexOf(']');
    if (firstBracket !== -1 && lastBracket !== -1) {
      try {
        const parsed = JSON.parse(raw.substring(firstBracket, lastBracket + 1));
        if (Array.isArray(parsed)) {
          parsed.forEach(o => ciOpportunities.push({ source: 'competitive_intel', ...o }));
          break;
        }
      } catch(e) { /* skip */ }
    }
  }
}

return [{ json: {
  etsyTemplates,
  etsyEbooks,
  ciOpportunities,
  totalEtsy: etsyTemplates.length + etsyEbooks.length,
  totalCI: ciOpportunities.length
} }];

const content = $json.content || [];
const textBlock = content.find(b => b.type === 'text');
const raw = textBlock ? textBlock.text : '';

const firstBracket = raw.indexOf('[');
const lastBracket  = raw.lastIndexOf(']');

let opportunities = [];
if (firstBracket !== -1 && lastBracket !== -1) {
  try {
    opportunities = JSON.parse(raw.substring(firstBracket, lastBracket + 1));
  } catch(e) {
    opportunities = [];
  }
}

opportunities = opportunities.filter(o => o.score >= 6.5 && o.title && o.niche);

if (opportunities.length === 0) {
  return [{ json: { title: '_no_results', niche: 'none', score: 0, status: 'pending', skip: true } }];
}

return opportunities.map(o => ({ json: o }));

// Supabase POST returns an array even for single inserts
const row = Array.isArray($json) ? ($json[0] || $json) : $json;
return [{ json: row }];
